import{a as t}from"./api-DveqSkcF.js";const o={getAll(){return t.get("/invoices")},getById(e){return t.get(`/invoices/${e}`)},getByStudentId(e){return t.get(`/invoices/student/${e}`)},getByContractId(e){return t.get(`/invoices/contract/${e}`)},getByStatus(e){return t.get(`/invoices/status/${e}`)},create(e){return t.post("/invoices",e)},update(e,n){return t.put(`/invoices/${e}`,n)},delete(e){return t.delete(`/invoices/${e}`)},getNextInvoiceCode(e,n,i){return t.get(`/invoices/next-code?invoiceType=${e}&month=${n}&year=${i}`)}};export{o as i};
